import React, { useState } from "react";
import OdontoQuadrado from "./OdontoQuadrado"; // o componente que postei na resposta anterior

const QUADRANTES = [
  {
    label: "Q1 (Superior Direito)",
    dentes: [18, 17, 16, 15, 14, 13, 12, 11],
  },
  {
    label: "Q2 (Superior Esquerdo)",
    dentes: [21, 22, 23, 24, 25, 26, 27, 28],
  },
  {
    label: "Q4 (Inferior Direito)",
    dentes: [48, 47, 46, 45, 44, 43, 42, 41],
  },
  {
    label: "Q3 (Inferior Esquerdo)",
    dentes: [31, 32, 33, 34, 35, 36, 37, 38],
  },
];

const ICONES = [
  { key: "normal", icon: "Normal", label: "Normal" },
  { key: "implante", icon: <img src="/img/dentes/implante.svg" alt="Implante" style={{width: 22}} />, label: "Implante" },
  { key: "coroa", icon: <img src="/img/icones/coroa.svg" alt="Coroa" style={{width: 22}} />, label: "Coroa" },
  { key: "extracao", icon: <img src="/img/icones/extracao.svg" alt="Extração" style={{width: 22}} />, label: "Extração" },
];

// Busca imagem SVG do dente conforme tratamento
function getSvgDente(num, tipo = "normal") {
  if (tipo && tipo !== "normal") {
    try {
      return require(`../img/dentes/${num}_${tipo}.svg`);
    } catch {
      try {
        return require(`../img/dentes/${tipo}.svg`);
      } catch {}
    }
  }
  try {
    return require(`../img/dentes/${num}.svg`);
  } catch {
    try {
      return require(`../img/dentes/generico.svg`);
    } catch {
      return "";
    }
  }
}

export default function OdontogramaDigital() {
  const [facesSelecionadas, setFacesSelecionadas] = useState({});
  const [dentesSelecionados, setDentesSelecionados] = useState({});
  const [tipoDente, setTipoDente] = useState({});

  function toggleFace(dente, face) {
    setFacesSelecionadas(fs => ({
      ...fs,
      [dente]: {
        ...fs[dente],
        [face]: !fs[dente]?.[face]
      }
    }));
  }

  function toggleDenteCheckbox(dente) {
    setDentesSelecionados(ds => ({
      ...ds,
      [dente]: !ds[dente]
    }));
  }

  function handleIconeClick(dente, key) {
    setTipoDente(td => ({
      ...td,
      [dente]: td[dente] === key ? "normal" : key
    }));
  }

  function renderDentes(arr) {
    return arr.map(num => (
      <div key={num} className="flex flex-col items-center mx-1 mb-3" style={{ minWidth: 54 }}>
        <input
          type="checkbox"
          checked={!!dentesSelecionados[num]}
          onChange={() => toggleDenteCheckbox(num)}
          className="accent-blue-600 mb-1"
          style={{width: 18, height: 18}}
        />
        <img
          src={getSvgDente(num, tipoDente[num] || "normal")}
          alt={`Dente ${num}`}
          style={{
            width: 38,
            height: 44,
            objectFit: "contain",
            marginBottom: -8,
            filter: tipoDente[num] === "extracao" ? "grayscale(1)" : undefined,
            opacity: tipoDente[num] === "extracao" ? 0.5 : 1,
            transition: "0.2s"
          }}
        />
        <OdontoQuadrado
          faces={facesSelecionadas[num] || {}}
          onClickFace={face => toggleFace(num, face)}
        />
        <span className="text-xs mt-1">{num}</span>
        {dentesSelecionados[num] && (
          <div className="flex gap-1 mt-1">
            {ICONES.map(ic => (
              <button
                key={ic.key}
                title={ic.label}
                onClick={() => handleIconeClick(num, ic.key)}
                className={`border rounded p-1 ${tipoDente[num] === ic.key ? "bg-blue-100" : "bg-white"} hover:bg-blue-50`}
                style={{ fontSize: 18, cursor: "pointer" }}
                type="button"
                tabIndex={0}
              >
                {ic.icon}
              </button>
            ))}
          </div>
        )}
      </div>
    ));
  }

  return (
    <div className="w-full max-w-6xl mx-auto p-2 md:p-6 bg-white rounded-xl shadow">
      <div className="text-lg font-bold text-center mb-6">Odontograma</div>

      {/* Grid de quadrantes: 2x2 (superior e inferior) */}
      <div
        className="grid grid-cols-1 md:grid-cols-2 gap-6"
        style={{alignItems: "start"}}
      >
        {/* Linha superior */}
        <div className="flex flex-col items-center w-full">
          <div className="w-full flex justify-between mb-1">
            <span className="font-semibold text-gray-600">Q1</span>
            <span className="font-semibold text-gray-600">Q2</span>
          </div>
          <div className="flex w-full justify-between">
            {/* Q1 (direita, invertido visualmente) */}
            <div className="flex flex-row-reverse">{renderDentes(QUADRANTES[0].dentes)}</div>
            {/* Q2 */}
            <div className="flex">{renderDentes(QUADRANTES[1].dentes)}</div>
          </div>
        </div>

        {/* Linha inferior */}
        <div className="flex flex-col items-center w-full mt-8 md:mt-0">
          <div className="w-full flex justify-between mb-1">
            <span className="font-semibold text-gray-600">Q4</span>
            <span className="font-semibold text-gray-600">Q3</span>
          </div>
          <div className="flex w-full justify-between">
            {/* Q4 (direita, invertido) */}
            <div className="flex flex-row-reverse">{renderDentes(QUADRANTES[2].dentes)}</div>
            {/* Q3 */}
            <div className="flex">{renderDentes(QUADRANTES[3].dentes)}</div>
          </div>
        </div>
      </div>

      {/* Legenda responsiva */}
      <div className="flex flex-wrap gap-4 mt-8 justify-center text-sm">
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-orange-400 border border-gray-400" /> Selecionado
        </div>
        <div>
          <span className="inline-block w-4 h-4 mr-1 align-middle rounded bg-gray-300 border border-gray-400" /> Não selecionado
        </div>
      </div>
    </div>
  );
}
